package org.apache.commons.jxpath.ri.model.dom;

import java.util.ArrayList;
import java.util.List;

import org.apache.commons.jxpath.ri.QName;
import org.apache.commons.jxpath.ri.model.NodeIterator;
import org.apache.commons.jxpath.ri.model.NodePointer;
import org.w3c.dom.Attr;
import org.w3c.dom.Element;
import org.w3c.dom.NamedNodeMap;
import org.w3c.dom.Node;

/**
 * An iterator of attributes of a DOM Node.
 *
 * @author Dmitri Plotnikov
 * @version $Revision$ $Date$
 */
public class DOMAttributeIterator implements NodeIterator {
    private NodePointer parent;
    private QName name;
    private List attributes;
    private int position = 0;

    public DOMAttributeIterator(NodePointer parent, QName name) {
        this.parent = parent;
        this.name = name;
        attributes = new ArrayList();
        Node node = (Node) parent.getNode();
        if (node.getNodeType() == Node.ELEMENT_NODE) {
            String lname = name.getName();
            if (!lname.equals("*")) {
                Attr attr = getAttribute((Element) node, name);
                if (attr != null) {
                    attributes.add(attr);
                }
            }
            else {
                NamedNodeMap map = node.getAttributes();
                int count = map.getLength();
                for (int i = 0; i < count; i++) {
                    Attr attr = (Attr) map.item(i);
                    if (testAttr(attr)) {
                        attributes.add(attr);
                    }
                }
            }
        }
    }

    private boolean testAttr(Attr attr) {
        String nodePrefix = DOMNodePointer.getPrefix(attr);
        String nodeLocalName = DOMNodePointer.getLocalName(attr);

        if (nodePrefix != null && nodePrefix.equals("xmlns")) {
            return false;
        }

        if (nodePrefix == null && nodeLocalName.equals("xmlns")) {
            return false;
        }

        String testLocalName = name.getName();
        if (testLocalName.equals("*") || testLocalName.equals(nodeLocalName)) {
            String testPrefix = name.getPrefix();

            if (equalStrings(testPrefix, nodePrefix)) {
                return true;
            }
            String testNS = null;
            if (testPrefix != null) {
                testNS = parent.getNamespaceURI(testPrefix);
            }
            String nodeNS = null;
            if (nodePrefix != null) {
                nodeNS = parent.getNamespaceURI(nodePrefix);
            }
            return equalStrings(testNS, nodeNS);
        }
        return false;
    }

    private static boolean equalStrings(String s1, String s2) {
        return s1 == s2 || s1 != null && s1.equals(s2);
    }

    private Attr getAttribute(Element element, QName name) {
        String testPrefix = name.getPrefix();
        String testNS = null;

        if (testPrefix != null) {
            testNS = parent.getNamespaceResolver().getNamespaceURI(testPrefix);
        }

        if (testNS != null) {
            Attr attr = element.getAttributeNodeNS(testNS, name.getName());
            if (attr != null) {
                return attr;
            }

            // This may mean that the parser does not support NS for
            // attributes, example - the version of Crimson bundled
            // with JDK 1.4.0
            NamedNodeMap nnm = element.getAttributes();
            for (int i = 0; i < nnm.getLength(); i++) {
                attr = (Attr) nnm.item(i);
                if (testAttr(attr)) {
                    return attr;
                }
            }
            return null;
        }
        return element.getAttributeNode(name.getName());
    }

    public NodePointer getNodePointer() {
        if (position == 0) {
            if (!setPosition(1)) {
                return null;
            }
            position = 0;
        }
        int index = position - 1;
        if (index < 0) {
            index = 0;
        }
        return new DOMAttributePointer(parent, (Attr) attributes.get(index));
    }

    public int getPosition() {
        return position;
    }

    public boolean setPosition(int position) {
        this.position = position;
        return position >= 1 && position <= attributes.size();
    }
}

package org.apache.commons.jxpath.ri.model.dom.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import io.cucumber.datatable.DataTable;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.util.List;
import java.util.Map;
import static org.junit.Assert.*;
import org.apache.commons.jxpath.JXPathContext;
import org.apache.commons.jxpath.ri.model.NodeIterator;
import org.apache.commons.jxpath.ri.model.NodePointer;

public class StepDefs {

    private Document document;
    private Element element;
    private JXPathContext context;
    private Object result;
    private Exception caughtException;

    @Given("a DOM element exists with the following attributes:")
    public void setupDOMElementWithAttributes(DataTable table) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            DocumentBuilder builder = factory.newDocumentBuilder();
            document = builder.newDocument();

            element = document.createElement("testElement");

            // Process the DataTable to add attributes
            List<Map<String, String>> rows = table.asMaps(String.class, String.class);
            for (Map<String, String> row : rows) {
                String name = row.get("Name");
                String value = row.get("Value");
                String namespaceURI = row.get("Namespace URI");

                if (namespaceURI != null && !namespaceURI.trim().isEmpty()) {
                    // Handle namespaced attribute
                    element.setAttributeNS(namespaceURI, name, value);
                } else {
                    // Handle regular attribute
                    element.setAttribute(name, value);
                }
            }

            document.appendChild(element);
            context = JXPathContext.newContext(document);
        } catch (Exception e) {
            caughtException = e;
        }
    }

    @When("I evaluate the XPath expression {string} on this element")
    public void evaluateWildcardExpression(String xpathExpression) {
        try {
            if (caughtException == null) {
                result = context.iteratePointers(xpathExpression);
            }
        } catch (Exception e) {
            caughtException = e;
        }
    }

    @Then("the result should contain both attributes")
    public void verifyResultContainsBothAttributes() {
        if (caughtException != null) {
            throw new RuntimeException(caughtException);
        }
        assertNotNull("Result should not be null", result);
        // Check that we got multiple attributes
        int count = 0;
        if (result instanceof NodeIterator) {
            NodeIterator iterator = (NodeIterator) result;
            int position = 1;
            while (iterator.setPosition(position)) {
                iterator.getNodePointer();
                count++;
                position++;
            }
        }
        assertTrue("Should contain at least two attributes", count >= 2);
    }

    @Then("the result should contain the value {string}")
    public void verifyResultContainsValue(String expectedValue) {
        if (caughtException != null) {
            throw new RuntimeException(caughtException);
        }

        // Need to recreate context to reset iteration
        JXPathContext freshContext = JXPathContext.newContext(document);
        Object values = freshContext.iteratePointers("@*/text()");
        boolean found = false;
        if (values instanceof NodeIterator) {
            NodeIterator iterator = (NodeIterator) values;
            int position = 1;
            while (iterator.setPosition(position)) {
                Object value = iterator.getNodePointer().getValue();
                if (expectedValue.equals(value.toString())) {
                    found = true;
                    break;
                }
                position++;
            }
        }
        assertTrue("Expected value '" + expectedValue + "' not found in results", found);
    }
}

